#include <bits/stdc++.h>
using namespace std;
int m,n,a,s[100001];
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a;
        s[i]=s[i-1]+a;
    }
    cin>>m;
    int l,r;
    for(int i=1;i<=m;i++){
        cin>>l>>r;
        cout<<s[r]-s[l-1]<<endl;
    }
    return 0;
}
